  '{"document_kind":"tour_product_full_page_v1","schema_version":1,"slug":"jeju-grand-highlights-loop","locale":"zh-TW","seo":{"pageTitle":"濟州漢拏山・柱狀節理・正房瀑布・城山日出峰小團一日遊 | AtoC Korea","metaDescription":"一天走訪濟州最具代表性的山景、海岸與地標景點。這條高效率環島小團路線帶你串連漢拏山、柱狀節理、正房瀑布與城山日出峰，特別適合停留時間有限的旅客。"},"catalog_card":{"slug":"jeju-grand-highlights-loop","title":"濟州經典大滿貫環島小團一日遊","subtitle":"從漢拏山到城山日出峰，一天看遍濟州代表風景。","region":"濟州環島","duration":"約 9–9.5 小時","stopsCount":5,"rating":0,"reviewCount":0,"badges":["適合只有一天的旅客","高密度亮點路線"],"heroImage":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=1920&q=80","thumbnail":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=600&q=80","priceLabel":"US$78 起 / 每人","shortCardDescription":"為時間有限的旅客打造的濟州高密度環島路線，一天走訪漢拏山、南岸海景與城山日出峰等代表級亮點。"},"headlineLine1":"濟州經典大滿貫環島","headlineLine2":"小團一日遊","price":{"amountLabel":"78","currency":"USD","per":"每人"},"hero":{"imageUrl":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=1920&q=80","imagePosition":"center 35%","tagline":"漢拏山、南岸絕景、瀑布與城山日出峰，一天走完濟州代表級亮點。","pills":["適合只有一天的旅客","小團出發","精選亮點"],"meta":{"duration":"約 9–9.5 小時","region":"濟州環島","stops":"5 個停靠點","rating":0,"ratingStars":0}},"subnavItems":[{"id":"overview","label":"行程概覽"},{"id":"itinerary","label":"詳細行程"},{"id":"details","label":"路線特色"},{"id":"faq","label":"常見問題"},{"id":"reviews","label":"旅客評價"}],"glanceItems":[{"icon":"camera","label":"拍照指數","value":"高"},{"icon":"mountain","label":"風景張力","value":"非常高"},{"icon":"footprints","label":"步行強度","value":"中等偏高"},{"icon":"cloud-rain","label":"雨天適合度","value":"中等"},{"icon":"users","label":"親子友善度","value":"普通"},{"icon":"gauge","label":"行程節奏","value":"偏快"}],"galleryItems":[{"id":1,"type":"photo","src":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=1200&q=80","location":"環島路線總覽","atmosphere":"一天看遍濟州代表風景","alt":"濟州環島小團路線總覽"},{"id":2,"type":"photo","src":"https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=800&q=80","location":"漢拏山高地步道","atmosphere":"山林開場","alt":"漢拏山御乘生岳步道景色"},{"id":3,"type":"photo","src":"https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?w=800&q=80","location":"南岸柱狀節理","atmosphere":"火山海岸質感","alt":"大浦柱狀節理海岸景觀"},{"id":4,"type":"photo","src":"https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=800&q=80","location":"正房瀑布","atmosphere":"瀑布與海岸交會","alt":"正房瀑布海岸景色"},{"id":5,"type":"photo","src":"https://images.unsplash.com/photo-1596402184320-417e7178b2cd?w=800&q=80","location":"城山日出峰","atmosphere":"經典地標收尾","alt":"城山日出峰火山口景觀"}],"itineraryStops":[{"number":1,"time":"09:30","duration":"70 分鐘","name":"漢拏山 御乘生岳","category":"漢拏山展望步道","description":"這一天從漢拏山高地開始最有感。御乘生岳以森林步道、火山坡面與開闊視野，替整條環島路線先建立起真正的山岳氣氛，讓後面的南岸與東岸風景更有層次。","image":"https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=800&q=80","highlights":["相對容易親近的漢拏山觀景點之一","沿途有明確的山林氛圍與高地感","比一般市區出發、直接看海的開場更有記憶點","很適合只有一天、但仍想感受漢拏山魅力的旅客"],"timeUsed":["抵達後說明步道與當天節奏","主要上坡步行至觀景點","短暫停留拍照後下行返回"],"whyOnRoute":"先從這裡出發，整天的路線才會有高度感、能量感，也更有「從漢拏山一路走到海邊」的濟州辨識度。","visitBasics":{"hours":"05:00 起可入山；實際依季節管制","closed":"可能因天候管制調整","admission":"免費","walking":"中等，上坡為主"},"convenience":{"restroom":"步道入口一帶","parking":"可停車"},"smartNotes":{"photo":"天氣晴朗時，觀景點的大景最出色，通常比近距離人像更有氣勢。","facilities":"僅有基本的步道口設施。","tip":"這一站比多數景點更看鞋子。遇到雨後或冬天時，建議一定穿抓地力較好的鞋。"}},{"number":2,"time":"11:15","duration":"40 分鐘","name":"大浦柱狀節理","category":"玄武岩海岸","description":"從山景轉進南岸之後，畫面會立刻變得俐落有力。柱狀節理把海浪、海風吹拂與火山岩柱一次拉滿，是午餐前非常有記憶點的南岸亮點。","image":"https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?w=800&q=80","highlights":["沿海排列的六角玄武岩柱景觀","與漢拏山開場形成明顯反差","停留時間不長，但視覺回報很高","是南濟州經典拍照點之一"],"timeUsed":["入口集合與簡短說明","主要海岸觀景步行","拍照後返回出口"],"whyOnRoute":"安排在上午後段，能讓南岸段落迅速成形，同時避免早上又再塞進一段過長步行。","visitBasics":{"hours":"09:00–18:00（最晚 17:40 入場）","closed":"全年開放","admission":"成人 2,000 / 兒童與青少年 1,000 韓元","walking":"輕鬆到中等"},"convenience":{"restroom":"入口區域","parking":"可停車（付費停車場）"},"smartNotes":{"photo":"海浪方向、海風與側光會讓畫面變化很大，通常以廣角海岸構圖最耐看。","facilities":"入口設施完整，觀景動線相對簡單。","tip":"這一站非常看風勢。就算市區天氣舒服，海邊也常常更涼、更強風。"}},{"number":3,"time":"12:15","duration":"60 分鐘","name":"午餐","category":"中段休息","description":"這條路線的午餐不是單純補空檔，而是撐住後半段品質的重要轉折。吃得從容一點，後面的正房瀑布與城山日出峰才不會變成單純趕路。","image":"https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=800&q=80","highlights":["在快節奏路線中真正把體力拉回來","替下午往東移動保留餘裕","對不同年齡層混合的小團特別重要","讓整天不會顯得過度壓縮"],"timeUsed":["抵達與入座","用餐與短暫休息","整理後準備出發"],"whyOnRoute":"把午餐放在這裡，可以保住下午行程的完整感，而不是讓後半段只剩下移動。","visitBasics":{"hours":"依餐廳營業時間","closed":"視店家而定","admission":"除非另有註明，現場自理","walking":"極少"},"convenience":{"restroom":"餐廳內設施","parking":"可停車"},"smartNotes":{"photo":"想從風景照稍微轉換一下節奏的話，這裡很適合拍食物或用餐氛圍。","facilities":"餐廳設施完整。","tip":"這一站很重要，因為比起硬趕時間，好好休息反而更能讓後半天維持體驗品質。"}},{"number":4,"time":"13:35","duration":"50 分鐘","name":"正房瀑布","category":"瀑布入海景觀","description":"午餐後，路線的氣氛會再次轉換。正房瀑布有石階、海風、水氣與海岸岩地，不只是「看瀑布」而已，而是非常有南濟州質感的一站。","image":"https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=800&q=80","highlights":["瀑布與岩岸海景一次看到","午餐後形成很好的景觀轉換","在高密度路線裡仍保有鮮明變化","讓往東移動前的南岸段更有記憶點"],"timeUsed":["抵達與入場動線整理","主要瀑布觀賞時段","拍照、短暫停留後返回"],"whyOnRoute":"它能讓南岸段落在前往城山前留下明確印象，而不是只有移動感。","visitBasics":{"hours":"09:00–17:20","closed":"全年開放","admission":"成人 2,000 / 兒童 1,000 韓元","walking":"中等，含階梯"},"convenience":{"restroom":"入口區域","parking":"可停車"},"smartNotes":{"photo":"靠近下方岩岸的位置最有氛圍，但地面與水氣會影響舒適度與腳步。","facilities":"入口附近有基本設施。","tip":"地圖上看起來不算遠，但實際上因為階梯與岩地，體感會比想像中再活動一些。"}},{"number":5,"time":"15:25","duration":"70 分鐘","name":"城山日出峰","category":"火山口壓軸","description":"城山日出峰作為最後一站很有說服力。走過漢拏山、南岸海景與正房瀑布之後，最後以濟州最具代表性的地標收尾，整天才會真正有「濟州走一圈」的完成感。","image":"https://images.unsplash.com/photo-1596402184320-417e7178b2cd?w=800&q=80","highlights":["以濟州代表地標為全天收尾","在高密度行程尾聲仍有很強的視覺回報","可依團體節奏調整為登頂或山腳觀景","對第一次來濟州、時間有限的旅客很有說服力"],"timeUsed":["抵達後說明動線與節奏","主要步行或山腳觀景時段","拍照與集合後返回濟州市"],"whyOnRoute":"把城山放在最後，收尾最有力，也最能讓整條路線呈現出真正的大滿貫效果。","visitBasics":{"hours":"依季節調整；售票時間亦隨季節變動","closed":"每月第一個星期一公休（若逢國定假日則順延）","admission":"成人 5,000 / 兒童 2,500 韓元","walking":"中等；若登頂則偏費體力"},"convenience":{"restroom":"山腳與周邊設施","parking":"大型停車場"},"smartNotes":{"photo":"多數時候，包含火山口與海岸線的大景會比只拍登頂特寫更有張力。","facilities":"山腳設施相對完整。","tip":"當天人潮、天氣與整團體力，會直接影響登頂體驗是否舒適。"}}],"routeFlowStops":[{"id":"01","name":"御乘生岳","theme":"漢拏山"},{"id":"02","name":"柱狀節理","theme":"海岸"},{"id":"03","name":"午餐","theme":"休息"},{"id":"04","name":"正房瀑布","theme":"瀑布"},{"id":"05","name":"城山日出峰","theme":"火山口"}],"routePhases":[{"label":"上午","range":"1-2","theme":"漢拏山到南岸","bgClass":"bg-sky-50/70","textClass":"text-sky-700","dotClass":"bg-sky-500"},{"label":"中段","range":"3-4","theme":"午餐與瀑布","bgClass":"bg-amber-50/70","textClass":"text-amber-700","dotClass":"bg-amber-500"},{"label":"壓軸","range":"5","theme":"城山日出峰","bgClass":"bg-emerald-50/70","textClass":"text-emerald-700","dotClass":"bg-emerald-500"}],"routeShapeIntro":{"title":"這一天怎麼走","subtitle":"先上漢拏山，再走南岸，最後以城山日出峰收尾。約 09:00 接送出發，17:40–18:00 返回濟州市。"},"whyTourWorks":{"bestFor":["只有一天停留濟州的旅客","上午抵達後想直接出發的旅客","想一次看濟州代表地標的旅客","平常願意走一些路的旅客"],"lessIdeal":["偏好慢節奏觀光的旅客","不想走階梯或上坡路段的旅客","年紀很小的孩童","推車行動為主的家庭"],"routeLogicSections":[{"title":"為時間有限的旅客而設計","icon":"clock-3","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"先上漢拏山","detail":"一早先走漢拏山段，能在還沒進入長距離移動前，先把整天的山岳氣氛與高度感建立起來。"},{"label":"南岸安排在中段","detail":"柱狀節理、午餐與正房瀑布把南岸段落串得很完整，不會讓西側到東側之間只剩下車程。"},{"label":"以城山作壓軸","detail":"城山放在最後最有收尾感，整條路線才會像真正的一日濟州大滿貫，而不是一般區域型小團。"}]},{"title":"為什麼這一天會比較有份量","icon":"mountain","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"兩段比較需要體力的步行","detail":"御乘生岳和城山日出峰，讓這條路線比一般小團行程更有活動量。"},{"label":"重點密度高於慢節奏","detail":"這條路線適合想在一天內看更多濟州代表景點的人，不是為了悠閒慢逛而設計。"},{"label":"如果時間有限，這樣很值得","detail":"對只有一天可用的旅客來說，這條路線用較快節奏換來更完整的代表景點覆蓋。"}]},{"title":"遇到現場條件變動時","icon":"wind","iconBg":"bg-slate-50/80","iconColor":"text-slate-600","items":[{"label":"漢拏山步道可能管制","detail":"御乘生岳步道會受到季節規定與天候管制影響。"},{"label":"海岸景點容易受風勢影響","detail":"柱狀節理與城山日出峰，是這一天最受風勢與天氣影響的兩段景觀。"},{"label":"回程時間可能略有浮動","detail":"車況、步行節奏與現場人潮，都可能讓最後返回時間有些微變動。"}]}]},"practicalAccordionItems":[{"id":"pickup","title":"接送與返回時間","preview":"早出發，傍晚回到濟州市","content":["08:30–09:00 於濟州市區範圍接送","約 17:40–18:00 返回濟州市","可依需求協助安排機場接送或上下車","實際集合時間會在前一晚確認"]},{"id":"walking","title":"步行與地形","preview":"比一般小團路線更需要活動量","content":["這條路線有兩段相對更需要體力的步行","御乘生岳包含上坡步道與階梯","正房瀑布需要走階梯並接近岩岸地形","若安排登頂，城山日出峰體感會更吃力","強烈建議穿著舒適、防滑的步行鞋"]},{"id":"weather","title":"天氣與臨時調整","preview":"多數天候可出發，但會視情況調整","content":["小雨時通常仍可正常進行，並做一般現場調整","風勢過強時，柱狀節理或城山的停留可能縮短","若漢拏山步道受管制，御乘生岳可能改為替代景點或調整內容","若景點臨時關閉，會依現場狀況改成替代停靠或調整節奏"]},{"id":"flight","title":"適合當天抵達或離開的旅客嗎？","preview":"很適合只有一天的旅客，但請保留時間彈性","content":["這條路線就是為想在一天內看濟州重點的旅客設計","對當天抵達或當天離開的旅客來說，通常也很合適","建議安排晚間班機離開","請務必預留足夠緩衝時間，以因應車況與步行節奏"]},{"id":"wear","title":"建議穿著與攜帶物品","preview":"好走的鞋、洋蔥式穿搭、輕便防風","content":["抓地力較好的步行鞋","因山區與海邊溫差而準備的分層穿搭","輕便防風外套","帽子與防曬用品","飲用水"]},{"id":"included","title":"包含 / 不包含項目","preview":"導遊、車輛、接送、門票","variant":"included","content":["專業英語導遊","小團車輛","濟州市區飯店接送","全程景點門票","瓶裝水","午餐（除非另有註明，現場自理）","個人購物","小費"]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"天氣以當日顯示為準"},"tomorrow":{"temp":"—","label":"每日更新"}},"seasonalVariations":[{"name":"春季","icon":"flower","description":"山區空氣清新，整體視野通常更舒服","tag":"平衡季節","bgClass":"bg-spring","iconColor":"text-pink-500"},{"name":"夏季","icon":"sun","description":"白天較長，海岸色彩也更鮮明","tag":"日照最長","bgClass":"bg-summer","iconColor":"text-sky-500"},{"name":"秋季","icon":"leaf","description":"能見度清晰，整條路線特別有收穫感","tag":"視野最佳","bgClass":"bg-autumn","iconColor":"text-amber-600"},{"name":"冬季","icon":"snow","description":"空氣更銳利，山與海的反差也更明顯","tag":"清透但偏涼","bgClass":"bg-winter","iconColor":"text-slate-500"}],"bookingTrustItems":[{"icon":"clock-3","title":"一天高效率","description":"專為時間有限旅客設計","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"mountain","title":"代表地標一次看","description":"從漢拏山一路到城山","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"小團出發","description":"路線調整更有彈性","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"下單後立即","title":"立即確認","detail":"收到預訂確認與路線摘要"},{"timing":"出發前 12 小時","title":"12 小時提醒","detail":"提供天氣更新與必要調整"},{"timing":"前一晚","title":"最終接送通知","detail":"確認實際接送時間與聯絡資訊"},{"timing":"出發當天早上","title":"當日行程提醒","detail":"依當天狀況提供簡短說明"},{"timing":"行程中","title":"景點即時提醒","detail":"每站提供現場動線與重點說明"},{"timing":"行程後","title":"行後協助","detail":"後續建議與補充資訊"}],"staticQuestions":[{"id":"one-day","question":"如果我在濟州只有一天，這條最適合嗎？","answer":"是的。這條路線就是為想在一天內看遍濟州代表級亮點的旅客設計，節奏會比一般小團更明快。"},{"id":"tiring","question":"這條行程會很累嗎？","answer":"相較一般小團，這條路線確實更有份量，因為包含兩段較需要體力的步行，以及更長的環島移動。"},{"id":"parents","question":"可以帶父母一起參加嗎？","answer":"要看平常步行習慣與體力狀況。如果希望節奏慢一點、輕鬆看景，這條不一定是最適合的選擇。"},{"id":"flight","question":"如果我當天抵達或當天離開，可以參加嗎？","answer":"多數情況下可以。這條路線對只有一天的旅客很有吸引力，但仍建議安排晚間班機，並保留足夠緩衝時間。"},{"id":"order","question":"景點順序會改嗎？","answer":"有可能。車況、天氣與現場人潮，都可能讓部分順序做微調，以維持整體路線更順。"},{"id":"seongsan-last","question":"為什麼把城山日出峰排在最後？","answer":"因為這樣收尾最有力。走完漢拏山、南岸與正房瀑布後，再用城山作結，整天會更有完成一圈濟州的感覺。"},{"id":"summit","question":"城山日出峰一定要走到頂嗎？","answer":"不一定。是否安排完整登頂，會依當天團體節奏、天氣與人潮狀況作調整。"}],"guestReviews":[],"reviewsSummary":{"averageRating":0,"totalReviews":0,"ratingDistribution":[{"stars":5,"count":0,"percentage":0},{"stars":4,"count":0,"percentage":0},{"stars":3,"count":0,"percentage":0},{"stars":2,"count":0,"percentage":0},{"stars":1,"count":0,"percentage":0}],"highlights":[{"label":"風景","count":0},{"label":"導遊","count":0},{"label":"節奏","count":0},{"label":"拍照點","count":0}]},"sticky_booking_bar":{"note":"checkout_tour_id resolves at runtime from Supabase / env; not part of static JSONB.","price":{"amountLabel":"78","currency":"USD","per":"每人"}}}'::jsonb
)
