  'persona',
  '{"document_kind":"tour_product_full_page_v1","schema_version":1,"slug":"jeju-grand-highlights-loop","locale":"es","seo":{"pageTitle":"Tour en grupo reducido por Hallasan, Jusangjeolli, Jeongbang y Seongsan en Jeju | AtoC Korea","metaDescription":"Un tour de un día por Jeju, ideal para viajeros con poco tiempo, que recorre Hallasan, Jusangjeolli, la cascada Jeongbang y Seongsan Ilchulbong en una sola jornada."},"catalog_card":{"slug":"jeju-grand-highlights-loop","title":"Tour en grupo reducido: Gran Ruta de los Imperdibles de Jeju","subtitle":"De Hallasan a Seongsan, todo en un solo día intenso.","region":"Toda la isla de Jeju","duration":"9-9.5 h","stopsCount":5,"rating":0,"reviewCount":0,"badges":["Ideal para visitantes de un solo día","Ruta de imperdibles a ritmo ágil"],"heroImage":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=1920&q=80","thumbnail":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=600&q=80","priceLabel":"Desde USD 78 por persona","shortCardDescription":"Una ruta premium por Jeju para quienes solo disponen de un día: Hallasan, la costa sur y Seongsan Ilchulbong en un itinerario de alto impacto."},"headlineLine1":"Gran Ruta de los Imperdibles de Jeju","headlineLine2":"Tour en grupo reducido","price":{"amountLabel":"78","currency":"USD","per":"persona"},"hero":{"imageUrl":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=1920&q=80","imagePosition":"center 35%","tagline":"Hallasan, acantilados de la costa sur, cascada y Seongsan, todo en un día potente para viajeros con tiempo limitado.","pills":["Ideal para visitantes de un solo día","Grupo reducido","Ruta premium de imperdibles"],"meta":{"duration":"9-9.5 h","region":"Toda la isla de Jeju","stops":"5 paradas","rating":0,"ratingStars":0}},"subnavItems":[{"id":"overview","label":"Resumen"},{"id":"itinerary","label":"Itinerario"},{"id":"details","label":"Detalles"},{"id":"faq","label":"Preguntas frecuentes"},{"id":"reviews","label":"Opiniones"}],"glanceItems":[{"icon":"camera","label":"Valor fotográfico","value":"Alto"},{"icon":"mountain","label":"Paisaje","value":"Muy alto"},{"icon":"footprints","label":"Caminata","value":"Media a alta"},{"icon":"cloud-rain","label":"Apto para lluvia","value":"Medio"},{"icon":"users","label":"Apto para familias","value":"Regular"},{"icon":"gauge","label":"Ritmo","value":"Ágil"}],"galleryItems":[{"id":1,"type":"photo","src":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=1200&q=80","location":"Resumen de la ruta","atmosphere":"La isla en un solo día","alt":"Resumen de la ruta de imperdibles de Jeju en un día"},{"id":2,"type":"photo","src":"https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=800&q=80","location":"Inicio en Hallasan","atmosphere":"Aire de montaña","alt":"Ambiente del sendero Eoseungsaengak en Hallasan"},{"id":3,"type":"photo","src":"https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?w=800&q=80","location":"Costa basáltica","atmosphere":"Contraste entre olas y acantilados","alt":"Acantilados basálticos costeros de Daepo Jusangjeolli"},{"id":4,"type":"photo","src":"https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=800&q=80","location":"Cascada hacia el mar","atmosphere":"Textura de la tarde","alt":"Entorno costero de la cascada Jeongbang"},{"id":5,"type":"photo","src":"https://images.unsplash.com/photo-1596402184320-417e7178b2cd?w=800&q=80","location":"Final en el cráter","atmosphere":"Cierre icónico","alt":"Cráter y costa de Seongsan Ilchulbong"}],"itineraryStops":[{"number":1,"time":"09:30","duration":"70 min","name":"Hallasan Eoseungsaengak","category":"Sendero panorámico de Hallasan","description":"El día comienza en el aire fresco de Hallasan. Eoseungsaengak ofrece una auténtica apertura de montaña, con sendero forestal, ladera volcánica y un mirador que hace que el resto del recorrido por la isla se sienta bien ganado desde el principio.","image":"https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=800&q=80","highlights":["Uno de los miradores más accesibles de Hallasan","Sendero de bosque con una clara atmósfera de montaña","Un inicio más potente que una ruta típica de ciudad a costa","Una primera parada memorable para viajeros con poco tiempo"],"timeUsed":["Llegada, explicación del sendero y ajuste de ritmo","Tramo principal de subida hasta el mirador","Breve pausa en la cima, fotos y descenso"],"whyOnRoute":"Comenzar aquí da altura, energía e identidad de Hallasan antes de bajar hacia la costa sur.","visitBasics":{"hours":"Entrada desde las 05:00; pueden aplicarse controles estacionales del sendero","closed":"Posibles restricciones por clima","admission":"Gratis","walking":"Subida moderada"},"convenience":{"restroom":"Zona de inicio del sendero","parking":"Disponible"},"smartNotes":{"photo":"Con buen tiempo, las fotos del cordal y del mirador funcionan mejor aquí; los encuadres amplios suelen quedar mejor que los retratos cerrados.","facilities":"Solo instalaciones básicas en el inicio del sendero.","tip":"El calzado importa más aquí que en la mayoría de las otras paradas, especialmente después de la lluvia o en meses fríos."}},{"number":2,"time":"11:15","duration":"40 min","name":"Acantilado de Daepo Jusangjeolli","category":"Costa basáltica","description":"Después de la montaña, la ruta se vuelve dramática en la costa sur. Jusangjeolli aporta energía marina, columnas de basalto y un fuerte cambio visual antes del almuerzo y de la segunda mitad del día.","image":"https://images.unsplash.com/photo-1500530855697-b586d89ba3ee?w=800&q=80","highlights":["Formaciones basálticas hexagonales junto al mar","Fuerte contraste de acantilado y mar tras el inicio en Hallasan","Parada compacta con gran impacto visual","Un clásico punto fotográfico del sur de Jeju"],"timeUsed":["Llegada y breve orientación en la entrada","Recorrido principal hasta el mirador costero","Parada para fotos y regreso"],"whyOnRoute":"Aporta una identidad clara de la costa sur sin sobrecargar la mañana con otra caminata larga.","visitBasics":{"hours":"09:00-18:00 (última entrada 17:40)","closed":"Abierto todo el año","admission":"Adultos 2,000 / Niños y jóvenes 1,000 KRW","walking":"Fácil a moderada"},"convenience":{"restroom":"Zona de entrada","parking":"Disponible (aparcamiento de pago)"},"smartNotes":{"photo":"La bruma del mar, la dirección de las olas y la luz lateral cambian mucho el ambiente; las composiciones amplias de costa suelen funcionar mejor.","facilities":"Buenas instalaciones en la entrada y ruta sencilla hasta el mirador.","tip":"El viento se nota aquí. Incluso en días despejados, la costa puede sentirse más fuerte y fresca que el interior."}},{"number":3,"time":"12:15","duration":"60 min","name":"Almuerzo","category":"Pausa del mediodía","description":"El almuerzo no es un simple relleno en esta ruta. Es el punto de reinicio que mantiene fuerte la segunda mitad del día, especialmente antes de Jeongbang y del tramo final hacia Seongsan.","image":"https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=800&q=80","highlights":["Un auténtico punto de recuperación en una ruta de ritmo ágil","Mejor equilibrio de energía antes del traslado al este","Útil para grupos activos de edades mixtas","Evita que el día se sienta excesivamente comprimido"],"timeUsed":["Llegada y acomodo","Comida y breve descanso","Preparación para la ruta de la tarde"],"whyOnRoute":"Colocado aquí, el almuerzo protege la calidad de la tarde en lugar de convertir la ruta en puro traslado.","visitBasics":{"hours":"Horario del restaurante","closed":"Varía","admission":"Pago directo salvo que se indique lo contrario","walking":"Mínima"},"convenience":{"restroom":"Instalaciones del restaurante","parking":"Disponible"},"smartNotes":{"photo":"Las fotos de comida funcionan bien aquí si se quiere una pausa entre tantas imágenes de paisaje.","facilities":"Servicios completos de restaurante.","tip":"Esta parada es clave porque la ruta funciona mejor cuando el grupo se recupera bien en vez de almorzar con prisa."}},{"number":4,"time":"13:35","duration":"50 min","name":"Cascada Jeongbang","category":"Cascada que cae al mar","description":"Jeongbang cambia otra vez el ambiente. Después del almuerzo, la ruta se vuelve más texturizada y costera, con escalones de piedra, brisa marina y una parada que se siente claramente como sur de Jeju, no como una visita genérica a una cascada.","image":"https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=800&q=80","highlights":["Cascada y costa rocosa en una sola parada compacta","Mayor contraste visual tras el almuerzo","Mantiene el impulso escénico antes del traslado al este","Buena variedad visual dentro de una ruta densa"],"timeUsed":["Llegada y acceso","Tramo principal de visita a la cascada","Tiempo para fotos y subida de regreso"],"whyOnRoute":"Evita que el tramo de la costa sur se sienta repetitivo y añade un contraste final más marcado antes de Seongsan.","visitBasics":{"hours":"09:00-17:50 (última entrada 17:10)","closed":"Abierto todo el año","admission":"Adultos 2,000 / Niños y jóvenes 1,000 KRW","walking":"Moderada con escalones"},"convenience":{"restroom":"Zona de entrada","parking":"Disponible"},"smartNotes":{"photo":"El encuadre amplio de cascada hacia el mar suele funcionar mejor que una toma cerrada centrada en la base.","facilities":"Instalaciones básicas para visitantes cerca de la entrada.","tip":"Esta parada se siente más física de lo que parece por los escalones de piedra y la subida de regreso."}},{"number":5,"time":"15:25","duration":"70 min","name":"Seongsan Ilchulbong","category":"Final en el cráter","description":"La ruta termina con el símbolo volcánico más icónico de Jeju. Después de Hallasan, la costa sur y Jeongbang, Seongsan funciona como la imagen final más potente del día: dramática, reconocible y perfecta para cerrar la experiencia.","image":"https://images.unsplash.com/photo-1596402184320-417e7178b2cd?w=800&q=80","highlights":["Cono de toba volcánica declarado por la UNESCO","El monumento más conocido de la isla para un cierre potente","Una vista gratificante al final de una jornada completa","Ritmo adaptable según el estado del grupo y la afluencia"],"timeUsed":["Llegada, ajuste de ritmo y acceso","Tramo principal a pie o subida a la cima según las condiciones","Vista del cráter o de la base, fotos y reagrupación"],"whyOnRoute":"Da al producto su identidad de gran final y justifica el gran circuito por Jeju como algo más que una excursión estándar.","visitBasics":{"hours":"07:00-20:00 (verano) / 07:30-19:00 (invierno)","closed":"Abierto todo el año","admission":"Adultos 5,000 / Niños y jóvenes 2,500 KRW","walking":"Moderada a exigente si se sube a la cima"},"convenience":{"restroom":"Zona de la base","parking":"Gran aparcamiento disponible"},"smartNotes":{"photo":"Las vistas amplias del cráter y la costa suelen superar a los encuadres muy cerrados solo de la cima.","facilities":"Buenas instalaciones en la zona de la base.","tip":"La experiencia de la cima puede variar bastante según la afluencia, el clima y la energía del grupo, por lo que conviene mantener flexibilidad aquí."}}],"routeFlowStops":[{"id":"01","name":"Eoseungsaengak","theme":"Hallasan"},{"id":"02","name":"Jusangjeolli","theme":"Acantilados"},{"id":"03","name":"Almuerzo","theme":"Pausa"},{"id":"04","name":"Jeongbang","theme":"Cascada"},{"id":"05","name":"Seongsan","theme":"Cráter"}],"routePhases":[{"label":"Mañana","range":"1-2","theme":"De Hallasan a la costa","bgClass":"bg-sky-50/70","textClass":"text-sky-700","dotClass":"bg-sky-500"},{"label":"Mediodía","range":"3-4","theme":"Almuerzo y cascada","bgClass":"bg-amber-50/70","textClass":"text-amber-700","dotClass":"bg-amber-500"},{"label":"Final","range":"5","theme":"Protagonista: Seongsan","bgClass":"bg-emerald-50/70","textClass":"text-emerald-700","dotClass":"bg-emerald-500"}],"routeShapeIntro":{"title":"Cómo fluye este día","subtitle":"Primero Hallasan, luego la costa sur y finalmente Seongsan para cerrar la jornada. Un circuito ágil por Jeju para viajeros con tiempo limitado."},"whyTourWorks":{"bestFor":["Visitantes de un solo día en Jeju","Viajeros que llegan por la mañana","Quienes quieren ver los íconos de la isla","Viajeros activos"],"lessIdeal":["Viajeros que buscan un ritmo lento","Personas que prefieren evitar escaleras o subidas","Niños muy pequeños","Grupos con muchos cochecitos"],"routeLogicSections":[{"title":"Por qué funciona para quienes solo tienen un día","icon":"clock-3","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"Hallasan primero, antes de que el día gane peso","detail":"Empezar en Eoseungsaengak da una identidad inicial más fuerte que una ruta clásica que comienza por la costa."},{"label":"La costa sur en la parte media","detail":"Jusangjeolli y Jeongbang aportan dramatismo y textura del sur sin perder impulso."},{"label":"Seongsan como gran cierre","detail":"Dejar Seongsan para el final le da a toda la ruta un último gran hito que justifica el circuito largo."}]},{"title":"Por qué se siente intensa pero vale la pena","icon":"mountain","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"Dos tramos activos en un solo día","detail":"Eoseungsaengak y Seongsan hacen que esta ruta sea más activa que una excursión estándar en grupo reducido."},{"label":"Más rápida que nuestras rutas habituales","detail":"Este producto está pensado para quienes quieren ver más, no para viajeros que buscan ir despacio."},{"label":"Un circuito premium de grandes imprescindibles","detail":"Su valor está en combinar montaña, acantilado, cascada y cráter en un solo día eficiente."}]},{"title":"Cuando cambian las condiciones","icon":"wind","iconBg":"bg-slate-50/80","iconColor":"text-slate-600","items":[{"label":"El viento importa en la costa","detail":"Jusangjeolli y Seongsan son las dos paradas paisajísticas más sensibles al clima."},{"label":"El acceso a Hallasan puede variar","detail":"Los controles del sendero o avisos meteorológicos pueden afectar la operativa en Eoseungsaengak."},{"label":"La hora de regreso puede ajustarse","detail":"El ritmo de caminata, el tráfico y la afluencia pueden mover ligeramente la vuelta final a Jeju City."}]}]},"practicalAccordionItems":[{"id":"pickup","title":"Recogida y horario de regreso","preview":"Salida temprana, regreso a Jeju City al final de la tarde","content":["Recogida en la zona de Jeju City entre 08:30 y 09:00","Regreso aproximado a Jeju City entre 17:40 y 18:00","Recogida o traslado al aeropuerto disponible bajo solicitud","La hora exacta se confirma la noche anterior"]},{"id":"walking","title":"Caminata y terreno","preview":"Más activa que nuestras rutas estándar","content":["Esta ruta incluye dos tramos de caminata más activos","Eoseungsaengak implica subida y escaleras","Jeongbang incluye escalones y un acceso junto a rocas","Seongsan puede sentirse exigente si se realiza la subida a la cima","Se recomiendan encarecidamente zapatos cómodos para caminar"]},{"id":"weather","title":"Clima y gestión de cierres","preview":"Opera en la mayoría de las condiciones con ajustes","content":["Lluvia ligera: el tour suele realizarse con ajustes normales","Viento fuerte: la exposición costera en Jusangjeolli o Seongsan puede acortarse","Controles de sendero en Hallasan: Eoseungsaengak puede sustituirse o ajustarse si el acceso está restringido","Cierres de sitios: se pueden usar paradas alternativas o cambios de ritmo cuando sea necesario"]},{"id":"flight","title":"Para llegadas o salidas el mismo día","preview":"Muy buena opción para visitas de un día, con margen de tiempo","content":["Esta ruta está pensada para viajeros que quieren ver los mayores imperdibles de Jeju en un solo día","Puede funcionar bien para quienes llegan o salen el mismo día","Se recomiendan vuelos de salida por la tarde-noche","Conviene dejar un margen amplio por tráfico y ritmo de caminata"]},{"id":"wear","title":"Qué llevar y cómo vestirse","preview":"Zapatos cómodos, capas y protección ligera contra el viento","content":["Zapatos con buen agarre","Capas para los cambios de temperatura entre montaña y costa","Chaqueta ligera cortaviento","Sombrero y protector solar","Botella de agua"]},{"id":"included","title":"Incluye / no incluye","preview":"Guía, vehículo, recogida y entradas","variant":"included","content":["Guía profesional de habla inglesa","Vehículo para grupo reducido","Recogida y regreso al hotel (Jeju City)","Todas las entradas","Agua embotellada","Almuerzo (pago directo en el restaurante)","Compras personales","Propinas"]}],"practicalWeatherStatic":{"today":{"temp":"—","label":"Tiempo actual · se muestra en la página"},"tomorrow":{"temp":"—","label":"Actualizado a diario"}},"seasonalVariations":[{"name":"Primavera","icon":"flower","description":"Aire de montaña fresco y mejor visibilidad en gran parte del circuito","tag":"Temporada equilibrada","bgClass":"bg-spring","iconColor":"text-pink-500"},{"name":"Verano","icon":"sun","description":"Más horas de luz y colores costeros más intensos","tag":"Días más largos","bgClass":"bg-summer","iconColor":"text-sky-500"},{"name":"Otoño","icon":"leaf","description":"La visibilidad más nítida hace que la ruta resulte especialmente gratificante","tag":"Mejor claridad","bgClass":"bg-autumn","iconColor":"text-amber-600"},{"name":"Invierno","icon":"snow","description":"Aire más limpio, más viento y mayor contraste entre montaña y costa","tag":"Claro pero fresco","bgClass":"bg-winter","iconColor":"text-slate-500"}],"bookingTrustItems":[{"icon":"clock-3","title":"Eficiente en un solo día","description":"Pensado para viajeros con tiempo limitado","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"mountain","title":"Lugares emblemáticos","description":"De Hallasan a Seongsan","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"Grupos reducidos","description":"Más flexibilidad en carretera","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"Inmediatamente","title":"Confirmación instantánea","detail":"Confirmación de reserva con resumen de la ruta"},{"timing":"12 horas antes","title":"Recordatorio 12 horas antes","detail":"Actualización del clima y posibles ajustes de la ruta"},{"timing":"La noche anterior","title":"Guía final de recogida","detail":"Hora exacta de recogida y datos de contacto"},{"timing":"La mañana del tour","title":"Notas del recorrido del día","detail":"Información matinal según las condiciones actuales"},{"timing":"Durante el tour","title":"Consejos parada por parada","detail":"Orientación en tiempo real en cada lugar"},{"timing":"Después del tour","title":"Soporte posterior","detail":"Seguimiento y recomendaciones"}],"staticQuestions":[{"id":"one-day","question":"¿Es esta la mejor opción si solo tengo un día en Jeju?","answer":"Sí. Esta ruta está pensada para viajeros que quieren ver los mayores imperdibles de Jeju en un solo día, con un ritmo más intenso que nuestras rutas estándar."},{"id":"tiring","question":"¿Es un tour cansado?","answer":"Puede resultar más exigente que nuestros tours habituales en grupo reducido porque incluye dos tramos de caminata más activos y un circuito más largo por la isla."},{"id":"parents","question":"¿Está bien para ir con los padres?","answer":"Depende del ritmo y de la comodidad al caminar. Esta ruta es mejor para adultos activos que para quienes buscan una jornada tranquila de sightseeing."},{"id":"flight","question":"¿Puedo unirme si llego o salgo el mismo día?","answer":"Sí, en muchos casos. Funciona bien para visitas de un solo día, pero se recomiendan vuelos de salida por la tarde-noche y un margen adicional."},{"id":"order","question":"¿Puede cambiar el orden de las paradas?","answer":"Sí. El tráfico, el clima y la afluencia pueden llevar a pequeños cambios en el orden para mantener una mejor fluidez general."},{"id":"seongsan-last","question":"¿Por qué Seongsan está al final?","answer":"Porque da un cierre más potente al día. Después de Hallasan, la costa sur y Jeongbang, Seongsan funciona como el hito final más icónico."},{"id":"summit","question":"¿Tengo que subir hasta arriba en Seongsan?","answer":"No siempre. La experiencia en la cima puede ajustarse según el ritmo del grupo, el clima y la afluencia del lugar."}],"guestReviews":[],"reviewsSummary":{"averageRating":0,"totalReviews":0,"ratingDistribution":[{"stars":5,"count":0,"percentage":0},{"stars":4,"count":0,"percentage":0},{"stars":3,"count":0,"percentage":0},{"stars":2,"count":0,"percentage":0},{"stars":1,"count":0,"percentage":0}],"highlights":[]},"sticky_booking_bar":{"note":"checkout_tour_id resolves at runtime from Supabase / env; not part of static JSONB.","price":{"amountLabel":"78","currency":"USD","per":"persona"}}}'::jsonb
)
